import ray

ray.init()

@ray.remote
def read_file(path: str) -> list:
    with open(path) as f:
        return f.read().split()

@ray.remote
def count_words(words: list) -> dict:
    from collections import Counter
    return dict(Counter(words))

@ray.remote
def merge_counts(*count_dicts) -> dict:
    from collections import Counter
    total = Counter()
    for d in count_dicts:
        total.update(d)
    return dict(total)

files = ["doc1.txt", "doc2.txt", "doc3.txt"]
word_refs = [count_words.remote(read_file.remote(f)) for f in files]
final = ray.get(merge_counts.remote(*word_refs))

import ray

ray.init(address="auto")  # Connect to running cluster

# --- Stage 1: Ingest ---
raw = ray.data.read_json("s3://events/2024-01-15/*.json.gz", parallelism=200)

# --- Stage 2: Parse and validate ---
def parse_event(batch: dict) -> dict:
    import json
    # Filter invalid records, extract fields
    valid = [e for e in batch["raw"] if e.get("user_id") and e.get("event_type")]
    return {"user_id": [e["user_id"] for e in valid],
            "event_type": [e["event_type"] for e in valid],
            "timestamp": [e["ts"] for e in valid]}

parsed = raw.map_batches(parse_event, batch_format="pandas")

# --- Stage 3: Compute per-user aggregates (stateful, using actors) ---
@ray.remote
class UserAggregator:
    def __init__(self):
        self.counts = {}

    def process(self, batch):
        for uid, etype in zip(batch["user_id"], batch["event_type"]):
            key = (uid, etype)
            self.counts[key] = self.counts.get(key, 0) + 1
        return batch

    def get_aggregates(self):
        return self.counts

aggregator = UserAggregator.remote()
parsed = parsed.map_batches(lambda b: ray.get(aggregator.process.remote(b)))

# --- Stage 4: Normalize features ---
def normalize(batch: dict) -> dict:
    import numpy as np
    for col in ["session_length", "page_views"]:
        if col in batch:
            arr = np.array(batch[col], dtype=float)
            batch[col] = ((arr - arr.mean()) / (arr.std() + 1e-8)).tolist()
    return batch

normalized = parsed.map_batches(normalize)

# --- Stage 5: Write output ---
normalized.write_parquet(
    "s3://features/processed/2024-01-15/",
    block_path_provider=ray.data.datasource.DefaultBlockWritePathProvider()
)
